module gpio_controller (
    input wire gpio_input,
    input wire control,
    input wire reset,
    output reg output_state
);
    always @(*) begin
        if (reset) begin
            output_state = 0;
        end else if (control) begin
            output_state = gpio_input;
        end
        // If control is low, output remains unchanged (no assignment here)
    end
endmodule
